import React from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import WelcomePage from "./pages/WelcomePage";
import AvatarSelection from "./pages/AvatarSelection";
import InteractionMode from "./pages/InteractionMode";

function App() {
    return (
        <Router>
            <Routes>
                {/* Route for the Welcome Page */}
                <Route path="/" element={<WelcomePage />} />

                {/* Route for the Avatar Selection Page */}
                <Route path="/choose-avatar" element={<AvatarSelection />} />

                <Route path="/interaction-mode" element={<InteractionMode />} />
                <Route path="/online" element={<h1>Online Interaction Page</h1>} />
                <Route path="/offline" element={<h1>Offline Interaction Page</h1>} />

            </Routes>
        </Router>
    );
}

export default App;
